#include <numeric>
#include <iostream>
#include <vector>
#include <stack>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    vector<int> postorderTraversal(TreeNode* root) {
        vector<int> res;
        if (!root) return res;
        stack<pair<TreeNode*, bool>> stk;
        stk.push({root, false});
        while (!stk.empty()) {
            auto& top = stk.top();
            TreeNode* node = top.first;
            bool visited = top.second;
            stk.pop();
            if (node) {
                if (visited) {
                    res.push_back(node->val);
                } else {
                    stk.push({node, true});
                    stk.push({node->right, false});
                    stk.push({node->left, false});
                }
            }
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    string val;
    vector<TreeNode*> nodes(n);
    for (int i = 0; i < n; i++) {
        cin >> val;
        if (val != "X") {
            nodes[i] = new TreeNode(stoi(val));
        } else {
            nodes[i] = nullptr;
        }
    }
    for (int i = 0; i < n; i++) {
        TreeNode* node = nodes[i];
        if (node) {
            int left_idx = 2 * i + 1;
            int right_idx = 2 * i + 2;
            if (left_idx < n) {
                node->left = nodes[left_idx];
            }
            if (right_idx < n) {
                node->right = nodes[right_idx];
            }
        }
    }
    TreeNode* root = nodes[0];
    Solution sol;
    vector<int> ans = sol.postorderTraversal(root);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
